parameters.jsCode:
// ==============================
// Parse Date & Time
// Supports:
// 1. YYYY-MM-DD
// 2. July 3, 2026
// ==============================

// Incoming body
const body = $input.item.json.body || {};

const name = body.name;
const phone = body.phone;
const email = body.email;
const service = body.service;
const dateStr = body.date;
const timeStr = body.time;

// -----------------------------
// Validate
// -----------------------------
if (!dateStr) {
  throw new Error("Appointment date is missing.");
}

if (!timeStr) {
  throw new Error("Appointment time is missing.");
}

// -----------------------------
// Parse Time
// -----------------------------
const timeMatch = timeStr.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);

if (!timeMatch) {
  throw new Error(`Invalid time format: ${timeStr}`);
}

let hours = parseInt(timeMatch[1], 10);
const minutes = parseInt(timeMatch[2], 10);
const period = timeMatch[3].toUpperCase();

if (period === "PM" && hours !== 12) hours += 12;
if (period === "AM" && hours === 12) hours = 0;

// -----------------------------
// Parse Date
// Accepts:
// 2026-07-03
// July 3, 2026
// -----------------------------
let year, month, day;

if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {

  // ISO Format
  [year, month, day] = dateStr.split("-").map(Number);

} else {

  // Natural language format
  const parsed = new Date(dateStr);

  if (isNaN(parsed.getTime())) {
    throw new Error(`Invalid date format: ${dateStr}`);
  }

  year = parsed.getFullYear();
  month = parsed.getMonth() + 1;
  day = parsed.getDate();
}

// -----------------------------
// Build RFC3339 (Google Calendar)
// -----------------------------
function buildDate(hour, minute) {

  return `${year}-${String(month).padStart(2,"0")}-${String(day).padStart(2,"0")}T${String(hour).padStart(2,"0")}:${String(minute).padStart(2,"0")}:00+05:30`;

}

// -----------------------------
// End Time (+30 mins)
// -----------------------------
let endHour = hours;
let endMinute = minutes + 30;

if (endMinute >= 60) {
  endMinute -= 60;
  endHour++;
}

if (endHour >= 24) {
  endHour = 0;
}

// -----------------------------
// Appointment ID
// -----------------------------
const appointmentId = `APT-${Date.now()}`;

// -----------------------------
// Return
// -----------------------------
return {
  json: {
    appointmentId,

    name,
    phone,
    email,
    service,

    date: `${year}-${String(month).padStart(2,"0")}-${String(day).padStart(2,"0")}`,
    time: timeStr,

    startDateTime: buildDate(hours, minutes),
    endDateTime: buildDate(endHour, endMinute)
  }
};

// Requested appointment
const booking = $('Parse Date & Time').first().json;

const requestedStart = new Date(booking.startDateTime);
const requestedEnd = new Date(booking.endDateTime);

// Events returned from Google Calendar
const events = $input.all();

let available = true;

for (const event of events) {

    // Skip empty items returned by "Always Output Data"
    if (!event.json.start || !event.json.end) {
        continue;
    }

    const eventStart = new Date(
        event.json.start.dateTime || event.json.start.date
    );

    const eventEnd = new Date(
        event.json.end.dateTime || event.json.end.date
    );

    // Overlap check
    const overlaps =
        requestedStart < eventEnd &&
        requestedEnd > eventStart;

    if (overlaps) {
        available = false;
        break;
    }
}

return [
{
    json: {
        ...booking,
        available
    }
}
];

